// Uygulama genelinde paylaşılan state yönetimi
// Kelime listesi, seans kuyruğu ve aktif ekran bilgisini tutar.

import { createContext, useContext, useState, useCallback } from "react";
import { DEFAULT_WORD_PAIRS } from "../constants/wordPairs";

// ── Context ──────────────────────────────────────────────
const AppContext = createContext(null);

// ── Provider ─────────────────────────────────────────────
export function AppProvider({ children }) {
  // Tüm kelime çiftleri (kalıcı liste)
  const [wordPairs, setWordPairs] = useState(DEFAULT_WORD_PAIRS);

  // Oyun ekranında kullanılacak aktif kuyruk
  const [gameQueue, setGameQueue] = useState([]);

  // Aktif ekran: "home" | "wordList" | "game" | "gameSingle"
  const [activeScreen, setActiveScreen] = useState("home");

  // Ses ayarı: "classic" | "speech" | "readWord" | "off"
  const [soundMode, setSoundMode] = useState("classic");

  // Navigasyon ──────────────────────────────────────────

  const goHome = useCallback(() => setActiveScreen("home"), []);

  const goWordList = useCallback(() => setActiveScreen("wordList"), []);

  const goInstructional = useCallback(() => setActiveScreen("instructional"), []);

  const goHowToUse = useCallback(() => setActiveScreen("howToUse"), []);

  // Tüm kelimelerle oyunu başlat
  const startGameWithAll = useCallback(() => {
    setGameQueue([...wordPairs]);
    setActiveScreen("game");
  }, [wordPairs]);

  // Tüm kelimelerle "Tekil Kelime Oyunu" (Dilim Nerede) başlat
  const startGameSingleWithAll = useCallback(() => {
    setGameQueue([...wordPairs]);
    setActiveScreen("gameSingle");
  }, [wordPairs]);

  // Seçili kelimelerle oyunu başlat
  const startGameWithQueue = useCallback((queue) => {
    setGameQueue(queue);
    setActiveScreen("game");
  }, []);

  // Seçili kelimelerle "Tekil Kelime Oyunu" başlat
  const startGameSingleWithQueue = useCallback((queue) => {
    setGameQueue(queue);
    setActiveScreen("gameSingle");
  }, []);

  // ── Kelime Yönetimi ─────────────────────────────────────

  const addWordPair = useCallback((pair) => {
    const newPair = {
      ...pair,
      id: `wp-${Date.now()}`,
    };
    setWordPairs((prev) => [...prev, newPair]);
  }, []);

  const updateWordPair = useCallback((id, updatedData) => {
    setWordPairs((prev) => prev.map((p) => (p.id === id ? { ...p, ...updatedData } : p)));
  }, []);

  const deleteWordPair = useCallback((id) => {
    setWordPairs((prev) => prev.filter((p) => p.id !== id));
  }, []);

  // ── Value ───────────────────────────────────────────────

  const value = {
    // State
    wordPairs,
    gameQueue,
    activeScreen,
    soundMode,
    // Navigasyon
    goHome,
    goWordList,
    goInstructional,
    goHowToUse,
    startGameWithAll,
    startGameSingleWithAll,
    startGameSingleWithQueue,
    startGameWithQueue,
    // Kelime yönetimi
    addWordPair,
    updateWordPair,
    deleteWordPair,
    // Ayarlar
    toggleSoundMode: useCallback(() => {
      setSoundMode((prev) => {
        if (prev === "classic") return "speech";
        if (prev === "speech") return "readWord";
        if (prev === "readWord") return "off";
        return "classic";
      });
    }, []),
  };

  return <AppContext.Provider value={value}>{children}</AppContext.Provider>;
}

// ── Hook ─────────────────────────────────────────────────
export function useApp() {
  const ctx = useContext(AppContext);
  if (!ctx) throw new Error("useApp must be used within AppProvider");
  return ctx;
}
