import React, { useState, useEffect, useCallback, useMemo } from "react";
import { useApp } from "../context/AppContext";
import { speakText, playPopSound } from "../utils/sound";

const ConfettiEffect = () => {
  const colors = ["#2ecc71", "#f1c40f", "#e74c3c", "#9b59b6", "#3498db", "#e67e22"];
  return (
    <div style={{ position: "fixed", top: 0, left: 0, width: "100%", height: "100%", overflow: "hidden", pointerEvents: "none", zIndex: 100 }}>
      {Array.from({ length: 80 }).map((_, i) => {
        const left = Math.random() * 100;
        const width = Math.random() * 8 + 6;
        const color = colors[Math.floor(Math.random() * colors.length)];
        const delay = Math.random() * 2.5;
        const duration = Math.random() * 2 + 2.5;
        return (
          <div
            key={i}
            style={{
              position: "absolute",
              top: "-5%",
              left: `${left}%`,
              width: `${width}px`,
              height: `${width * 1.5}px`,
              backgroundColor: color,
              opacity: 0.9,
              animation: `confettiFall ${duration}s linear ${delay}s infinite, confettiSway ${duration * 0.5}s ease-in-out ${delay}s infinite alternate`,
            }}
          />
        );
      })}
    </div>
  );
};

// Helper to shuffle array
const shuffleArray = (array) => {
  const shuffled = [...array];
  for (let i = shuffled.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [shuffled[i], shuffled[j]] = [shuffled[j], shuffled[i]];
  }
  return shuffled;
};

export default function GameModeSingle() {
  const { gameQueue, goHome, soundMode } = useApp();

  // Orijinal ikili kelimeleri tekil listeye çevirme (flatten)
  const flattenedList = useMemo(() => {
    if (!gameQueue || gameQueue.length === 0) return [];
    
    return gameQueue.flatMap((pair) => {
      const items = [];
      const p1 = pair.position1 || pair.position || "front";
      const p2 = pair.position2 || pair.position || "front";

      if (pair.word1 && p1 !== "mid") {
        items.push({
          id: `${pair.id}-1`,
          word: pair.word1,
          image: pair.word1Img,
          position: p1,
        });
      }
      if (pair.word2 && p2 !== "mid") {
        items.push({
          id: `${pair.id}-2`,
          word: pair.word2,
          image: pair.word2Img,
          position: p2,
        });
      }
      return items;
    });
  }, [gameQueue]);

  const [mode, setMode] = useState("sequential"); // "sequential" | "random"
  const [words, setWords] = useState([]);
  const [currentIndex, setCurrentIndex] = useState(0);
  
  // feedback: null | "success" | "error"
  const [feedback, setFeedback] = useState(null);
  const [isFinished, setIsFinished] = useState(false);

  // Mod değiştiğinde veya liste geldiğinde listeyi oluştur
  useEffect(() => {
    if (flattenedList.length === 0) return;
    
    let nextList = [...flattenedList];
    if (mode === "random") {
      nextList = shuffleArray(nextList);
    }
    
    setWords(nextList);
    setCurrentIndex(0);
    setFeedback(null);
    setIsFinished(false);
  }, [mode, flattenedList]);

  const currentWordObj = words[currentIndex];

  const speakingTimeoutRef = React.useRef(null);

  const getImgUrl = (path) => {
    if (!path) return null;
    if (path.startsWith("http")) return path;
    if (!path.startsWith("/")) path = "/" + path;
    return process.env.PUBLIC_URL + path;
  };

  // Seslendirme logic'i
  const readCurrentWord = useCallback((playFull = true) => {
    if (soundMode === "off" || !currentWordObj) return;
    
    if ("speechSynthesis" in window) {
      window.speechSynthesis.cancel();
      
      if (speakingTimeoutRef.current) {
        clearTimeout(speakingTimeoutRef.current);
      }
      
      if (playFull === true) {
        const questionMsg = new SpeechSynthesisUtterance("Dilim Nerede?");
        questionMsg.lang = "tr-TR";
        questionMsg.rate = 1.0; 
        
        questionMsg.onend = () => {
          speakingTimeoutRef.current = setTimeout(() => {
            const wordMsg = new SpeechSynthesisUtterance(currentWordObj.word);
            wordMsg.lang = "tr-TR";
            wordMsg.rate = 1.0;
            wordMsg.volume = 1.0;
            wordMsg.pitch = 1.1;
            window.speechSynthesis.speak(wordMsg);
          }, 300);
        };

        window.speechSynthesis.speak(questionMsg);
      } else {
        const wordMsg = new SpeechSynthesisUtterance(currentWordObj.word);
        wordMsg.lang = "tr-TR";
        wordMsg.rate = 1.0;
        wordMsg.volume = 1.0;
        wordMsg.pitch = 1.1;
        window.speechSynthesis.speak(wordMsg);
      }
    }
  }, [currentWordObj, soundMode]);

  // Yeni kelimeye geçildiğinde otomatik seslendir (eğer ayar açıksa)
  useEffect(() => {
    if (currentWordObj && soundMode !== "off") {
      readCurrentWord();
    }
  }, [currentIndex, currentWordObj, soundMode, readCurrentWord]);

  // Boş liste kontrolü
  if (flattenedList.length === 0) {
    return (
      <div className="screen" style={{ justifyContent: "center" }}>
        <h2>Kelime bulunamadı!</h2>
        <button onClick={goHome} className="lk-back-btn" style={{ marginTop: 20 }}>
          <span>←</span> Ana Sayfaya Dön
        </button>
      </div>
    );
  }

  // Kullanıcı cevap verdiğinde
  const handleAnswer = (selectedPos) => {
    if (feedback) return; // Zaten bir animasyon/cevap dönüyorsa blokla

    const isCorrect = currentWordObj.position === selectedPos;

    if (isCorrect) {
      // BAŞARI
      setFeedback("success");
      if (soundMode !== "off") {
        playPopSound();
        speakText("Harika!");
      }
      
      // 2 saniye sonra sonraki kelimeye geç
      setTimeout(() => {
        handleNextWord();
      }, 2000);
      
    } else {
      // HATA
      setFeedback("error");
      if (soundMode !== "off") {
        speakText("Bu yanlış oldu, hadi tekrar deneyelim.");
      }
      
      // 1.5 saniye sonra hata animasyonunu kaldır
      setTimeout(() => {
        setFeedback(null);
      }, 1500);
    }
  };

  const handleNextWord = () => {
    setFeedback(null);
    if (currentIndex < words.length - 1) {
      setCurrentIndex((prev) => prev + 1);
    } else {
      setIsFinished(true);
      if (soundMode !== "off") {
        playPopSound();
        speakText("Tebrikler! Başarıyla tamamladınız!");
      }
    }
  };

  if (isFinished) {
    return (
      <div className="screen" style={{ justifyContent: "center", padding: 20 }}>
        <ConfettiEffect />
        
        <div style={{ position: "relative", zIndex: 110, display: "flex", flexDirection: "column", alignItems: "center" }}>
          <div style={{ fontSize: "6rem", marginBottom: 10, animation: "bounceScale 1s ease-in-out infinite alternate" }}>
            🏆
          </div>
          <h1 style={{ 
            fontFamily: "'Baloo 2', cursive", 
            fontSize: "clamp(2rem, 6vw, 3.5rem)", 
            color: "#2d6e40", 
            textAlign: "center", 
            marginBottom: 40,
            textShadow: "0 4px 12px rgba(46, 204, 113, 0.3)"
          }}>
            Tebrikler!<br/>Başarıyla Tamamladınız!
          </h1>
          
          <button 
            onClick={goHome} 
            className="lk-back-btn"
            style={{ 
              background: "linear-gradient(145deg, #f39c12, #e67e22)", 
              color: "#fff", 
              fontSize: "1.2rem",
              padding: "16px 32px",
              borderRadius: 30,
              boxShadow: "0 6px 22px rgba(243,156,18,0.4), 0 3px 0 #d68910" 
            }}
          >
            <span>🏠</span> Ana Menüye Dön
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="screen" style={{ padding: "10px" }}>
      {/* Üst Kısım / Navigasyon - Geri */}
      <div className="lk-header">
        <button onClick={goHome} className="lk-back-btn" style={{ width: 85, justifyContent: "center" }}>
          <span>←</span> Çıkış
        </button>
        <span className="lk-header__title" style={{ flex: 1, textAlign: "center" }}>Dilim Nerede?</span>
        <div className="game__nav-counter" style={{ width: 85, textAlign: "right" }}>
          {currentIndex + 1} / {words.length}
        </div>
      </div>

      <div style={{ width: "100%", maxWidth: 680, display: "flex", justifyContent: "center", padding: "0 10px", marginBottom: 4 }}>
        {/* Mod Değiştirici */}
        <button 
          onClick={() => setMode(mode === "sequential" ? "random" : "sequential")}
          className="lk-back-btn"
          style={{ background: "#f0f4f1", color: "#5a9a6a", border: "1px solid #d4eedd", fontSize: "0.80rem", padding: "6px 12px" }}
        >
          🔄 {mode === "sequential" ? "Sıralı Mod → Rastgele Yap" : "Rastgele Mod → Sıralı Yap"}
        </button>
      </div>

      {/* İçik Alan */}
      <div style={{ flex: 1, display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", width: "100%", maxWidth: 680, padding: "0 10px" }}>
        
        {/* Soru Başlığı */}
        <h1 style={{ 
          fontFamily: "'Baloo 2', cursive", 
          fontSize: "clamp(1.4rem, 4vw, 2rem)", 
          color: "#2d6e40", 
          textAlign: "center", 
          marginBottom: 12,
          textShadow: "0 2px 10px rgba(46, 204, 113, 0.2)"
        }}>
          Dilim Nerede?<br />Önde mi, Arkada mı?
        </h1>

        {/* Aktif Kelime Kartı */}
        <div style={{ position: "relative", width: "100%", maxWidth: 400, margin: "0 auto 16px" }}>
          <div className="game__word-card" style={{ cursor: "default", minHeight: 200, justifyContent: "center", border: "4px solid #d4eedd", padding: 12 }}>
            {currentWordObj?.image && (
              <img 
                key={currentWordObj.id + "-img"}
                src={getImgUrl(currentWordObj.image)} 
                alt={currentWordObj.word} 
                style={{ width: 140, height: 140, objectFit: "contain", marginBottom: 8 }} 
                onError={(e) => { 
                  e.target.style.display = "none"; 
                }}
              />
            )}
            <div className="game__word-card__word" style={{ fontSize: "2.4rem", padding: 0 }}>
              {currentWordObj?.word}
            </div>
            {/* Tekrar dinleme butonu */}
            <button 
              onClick={() => readCurrentWord(false)}
              style={{
                position: "absolute",
                top: 10,
                right: 10,
                background: "rgba(255,255,255,0.9)",
                border: "none",
                borderRadius: "50%",
                width: 44,
                height: 44,
                fontSize: "1.4rem",
                cursor: "pointer",
                boxShadow: "0 2px 8px rgba(0,0,0,0.1)"
              }}
              title="Tekrar Dinle"
            >
              🔊
            </button>
          </div>

          {/* Feedback Overlay */}
          {feedback && (
            <div className="feedback-overlay">
              {feedback === "success" ? (
                <div className="feedback-success-text">Harika! 🎉</div>
              ) : (
                <div className="feedback-error-text">Tekrar Deneyelim</div>
              )}
            </div>
          )}
        </div>

        {/* Seçenek Butonları */}
        <div style={{ display: "flex", gap: 12, width: "100%", justifyContent: "center" }}>
          <button 
            className="game-single__btn game-single__btn--front"
            onClick={() => handleAnswer("front")}
          >
            🌟 Önde
          </button>
          
          <button 
            className="game-single__btn game-single__btn--back"
            onClick={() => handleAnswer("back")}
          >
            🔆 Arkada
          </button>
        </div>

      </div>
    </div>
  );
}
