// Oyun Ekranı (Game Screen)
// Üstte tırtıl, altta aktif kelime çifti kartları.
// Karta dokunulduğunda tırtılın ilgili bölgesi parlar.
// Önceki / Sonraki butonlarıyla navigasyon.

import { useState } from "react";
import { useApp }   from "../context/AppContext";
import Background   from "../components/Background";
import CaterpillarSVG from "../components/CaterpillarSVG";
import { playPopSound, speakText } from "../utils/sound";

const POSITION_META = {
  front: { icon: "🌟", label: "Ön Pozisyon",   pillClass: "game__zone-pill--front" },
  back:  { icon: "🔆", label: "Arka Pozisyon",  pillClass: "game__zone-pill--back"  },
};

// Maksimum gösterilecek ilerleme noktası sayısı (çok uzun listelerde taşmasın)
const MAX_DOTS = 20;

export default function GameScreen() {
  const { gameQueue, goHome, goWordList, soundMode } = useApp();

  // Mevcut sıra indeksi
  const [currentIdx, setCurrentIdx]   = useState(0);
  // Aktif parlaklık: karta dokunulduğunda set edilir, tırtıl parlar
  const [activeZone, setActiveZone]   = useState(null);
  // Hangi karta dokunuldu (görsel feedback için)
  const [tappedCard, setTappedCard]   = useState(null); // "word1" | "word2" | null

  const total       = gameQueue.length;
  const currentPair = gameQueue[currentIdx] || null;

  // ── Navigasyon ──────────────────────────────────────
  const goPrev = () => {
    if (currentIdx > 0) {
      setCurrentIdx((i) => i - 1);
      setActiveZone(null);
      setTappedCard(null);
    }
  };

  const goNext = () => {
    if (currentIdx < total - 1) {
      setCurrentIdx((i) => i + 1);
      setActiveZone(null);
      setTappedCard(null);
    }
  };

  // ── Kart tıklama ────────────────────────────────────
  const handleCardTap = (cardKey) => {
    if (!currentPair) return;
    // Aynı karta tekrar basılırsa söndür
    if (tappedCard === cardKey) {
      setTappedCard(null);
      setActiveZone(null);
    } else {
      const pos = cardKey === "word1" 
        ? (currentPair.position1 || currentPair.position || "front")
        : (currentPair.position2 || currentPair.position || "front");
        
      // İlk tıklanışta/aktifleşmede sese göre uyar
      if (soundMode === "classic") {
        playPopSound();
      } else if (soundMode === "speech") {
        const textToSpeak = pos === "front" ? "Ön" : (pos === "back" ? "Arka" : "Orta");
        speakText(textToSpeak);
      } else if (soundMode === "readWord") {
        const wordText = cardKey === "word1" ? currentPair.word1 : currentPair.word2;
        const msg = new SpeechSynthesisUtterance(wordText);
        msg.lang = "tr-TR";
        msg.rate = 1.0;
        msg.volume = 1.0;
        msg.pitch = 1.1;
        if ("speechSynthesis" in window) {
          window.speechSynthesis.cancel();
          window.speechSynthesis.speak(msg);
        }
      }
      
      setTappedCard(cardKey);
      setActiveZone(pos);
    }
  };

  // ── Boş kuyruk koruması ─────────────────────────────
  if (total === 0) {
    return (
      <div className="screen">
        <Background />
        <div className="lk-header" style={{ gap: "4px" }}>
          <div style={{ flex: 1, display: "flex", justifyContent: "flex-start" }}>
            <button className="lk-back-btn" onClick={goHome}>← Ana Sayfa</button>
          </div>
          <span className="lk-header__title" style={{ flex: "0 1 auto", textAlign: "center", lineHeight: "1.2" }}>🐛 Oyun</span>
          <div style={{ flex: 1 }} />
        </div>
        <div style={{ flex: 1, display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", gap: 16, position: "relative", zIndex: 5 }}>
          <p style={{ fontFamily: "'Baloo 2', cursive", fontSize: "1.1rem", color: "#3d7a52", fontWeight: 800 }}>
            Kelime listesi boş.
          </p>
          <button className="home__btn home__btn--secondary" onClick={goWordList}>
            📋 Kelime Ekle
          </button>
        </div>
      </div>
    );
  }

  const pos1 = currentPair ? currentPair.position1 || currentPair.position || "front" : "front";
  const pos2 = currentPair ? currentPair.position2 || currentPair.position || "front" : "front";
  const activePos = tappedCard === "word1" ? pos1 : (tappedCard === "word2" ? pos2 : null);
  const meta = activePos ? POSITION_META[activePos] : null;
  const showDots = total <= MAX_DOTS;

  const getImgUrl = (path) => {
    if (!path) return null;
    if (path.startsWith("http")) return path;
    if (!path.startsWith("/")) path = "/" + path;
    return process.env.PUBLIC_URL + path;
  };

  return (
    <div className="screen">
      <Background />

      {/* Header */}
      <div className="lk-header" style={{ gap: "4px" }}>
        <div style={{ flex: 1, display: "flex", justifyContent: "flex-start" }}>
          <button className="lk-back-btn" onClick={goHome}>← Ana Sayfa</button>
        </div>
        <span className="lk-header__title" style={{ flex: "0 1 auto", textAlign: "center", lineHeight: "1.2", margin: "0 4px" }}>🐛 Lingual Kontrol</span>
        <div style={{ flex: 1, display: "flex", justifyContent: "flex-end" }}>
          <button className="lk-back-btn" onClick={goWordList}>📋 Liste</button>
        </div>
      </div>

      {/* Tırtıl alanı */}
      <div className="game__caterpillar-area" style={{ marginBottom: "12px" }}>
        <div style={{ position: "relative", display: "flex", alignItems: "center", justifyContent: "center" }}>
          <CaterpillarSVG activeZone={activeZone} />
        </div>
      </div>

      {/* Alt alan */}
      <div className="game__bottom">

        {/* İlerleme noktaları */}
        {showDots && (
          <div className="game__progress">
            {gameQueue.map((_, i) => (
              <div
                key={i}
                className={`game__progress-dot${
                  i === currentIdx ? " active" : i < currentIdx ? " done" : ""
                }`}
              />
            ))}
          </div>
        )}

        {/* Kelime kartları */}
        <div className="game__card-row">
          {/* Kart 1 Container */}
          <div style={{ display: "flex", flexDirection: "column", alignItems: "center", gap: "2px" }}>
            <span style={{ fontFamily: "'Baloo 2', cursive", fontSize: "0.95rem", fontWeight: 800, color: "#3d7a52", letterSpacing: "0.5px" }}>
              {pos1 === "front" ? "ÖN" : (pos1 === "back" ? "ARKA" : "")}
            </span>
            {/* Kart 1 */}
            <div
              className={`game__word-card${tappedCard === "word1" ? " tapped" : ""}`}
              onClick={() => handleCardTap("word1")}
              style={{ width: "100%" }}
            >
              {currentPair.word1Img && (
                <img
                  key={currentPair.id + "-img1"}
                  src={getImgUrl(currentPair.word1Img)}
                  alt={currentPair.word1}
                  className="game__word-card__img"
                  onError={(e) => { 
                    e.target.style.display = "none"; 
                  }}
                />
              )}
              <span className="game__word-card__word">{currentPair.word1}</span>
            </div>
          </div>

          {/* Kart 2 Container */}
          <div style={{ display: "flex", flexDirection: "column", alignItems: "center", gap: "2px" }}>
            <span style={{ fontFamily: "'Baloo 2', cursive", fontSize: "0.95rem", fontWeight: 800, color: "#3d7a52", letterSpacing: "0.5px" }}>
              {pos2 === "front" ? "ÖN" : (pos2 === "back" ? "ARKA" : "")}
            </span>
            {/* Kart 2 */}
            <div
              className={`game__word-card${tappedCard === "word2" ? " tapped" : ""}`}
              onClick={() => handleCardTap("word2")}
              style={{ width: "100%" }}
            >
              {currentPair.word2Img && (
                <img
                  key={currentPair.id + "-img2"}
                  src={getImgUrl(currentPair.word2Img)}
                  alt={currentPair.word2}
                  className="game__word-card__img"
                  onError={(e) => { 
                    e.target.style.display = "none"; 
                  }}
                />
              )}
              <span className="game__word-card__word">{currentPair.word2}</span>
            </div>
          </div>
        </div>

        {/* Navigasyon */}
        <div className="game__nav">
          <button
            className="game__nav-btn"
            onClick={goPrev}
            disabled={currentIdx === 0}
          >
            ← Önceki
          </button>

          <span className="game__nav-counter">
            {currentIdx + 1} / {total}
          </span>

          <button
            className="game__nav-btn"
            onClick={goNext}
            disabled={currentIdx === total - 1}
          >
            Sonraki →
          </button>
        </div>

        {/* Pozisyon pill */}
        <div className={`game__zone-pill ${meta ? meta.pillClass : "game__zone-pill--inactive"}`} style={{ opacity: meta ? 1 : 0.5, marginTop: "8px" }}>
          {meta ? (<>{meta.icon} {meta.label}</>) : "Pozisyonu Görmek İçin Seçin"}
        </div>

      </div>
    </div>
  );
}
