// Ana Sayfa (Home Screen)
// Uygulamanın giriş ekranı. İki aksiyonla başlar:
//  - "Başla"       → tüm kelime listesiyle oyunu başlatır
//  - "Kelime Listesi" → kelime yönetim ekranına geçer

import { useState } from "react";
import { useApp } from "../context/AppContext";
import Background from "../components/Background";
import CaterpillarSVG from "../components/CaterpillarSVG";
import GameSingleConfigModal from "../components/GameSingleConfigModal";

export default function Home() {
  const { startGameWithAll, startGameSingleWithAll, goWordList, goInstructional, goHowToUse, soundMode, toggleSoundMode } = useApp();
  const [showSingleModal, setShowSingleModal] = useState(false);

  const getSoundButtonText = () => {
    if (soundMode === "classic") return "🔊 Ses: Klasik Mod";
    if (soundMode === "speech") return "🗣️ Ses: Pozisyon (Ön/Arka)";
    if (soundMode === "readWord") return "💬 Ses: Kelime Oku";
    return "🔇 Ses: Kapalı";
  };

  return (
    <div className="screen">
      <Background />

      {/* Başlık */}
      <div className="lk-header" style={{ justifyContent: "center", paddingBottom: 0 }}>
        <span className="lk-header__title">🐛 Lingual Kontrol</span>
      </div>

      {/* Tırtıl görseli */}
      <div style={{ position: "relative", zIndex: 5, marginTop: 0 }}>
        <CaterpillarSVG activeZone={null} />
      </div>

      {/* İçerik */}
      <div className="home__content" style={{ gap: 8, paddingBottom: 5 }}>
        <div style={{ marginTop: 0 }}>
          <h1 className="home__hero-title">Dilin Nerede?</h1>
          <p className="home__hero-sub" style={{ marginTop: 2 }}>
            Lingual Pozisyon Görsel İpucu Aracı
          </p>
        </div>

        <div className="home__buttons" style={{ gap: 8, marginTop: 5 }}>
          <button className="home__btn home__btn--primary" onClick={startGameWithAll}>
            <span>▶</span> Başla (İkili)
          </button>
          <button 
            className="home__btn" 
            onClick={() => setShowSingleModal(true)}
            style={{ 
              background: "linear-gradient(145deg, #f39c12, #e67e22)", 
              color: "#fff",
              boxShadow: "0 6px 22px rgba(243,156,18,0.4), 0 2px 0 #d68910"
            }}
          >
            <span>🎯</span> Dilim Nerede?
          </button>
          <button className="home__btn home__btn--secondary" onClick={goWordList}>
            <span>📋</span> Kelime Listesi
          </button>
          <button className="home__btn home__btn--secondary" onClick={goInstructional}>
            <span>💡</span> Dilimin Pozisyonu
          </button>
        </div>

        {/* Ayarlar */}
        <div style={{ 
          marginTop: 5, 
          width: "280px", 
          maxWidth: "100%", 
          display: "flex", 
          justifyContent: "space-between",
          gap: 10
        }}>
          <button 
            onClick={toggleSoundMode}
            style={{ 
              flex: 1,
              background: "transparent", 
              border: "2px solid rgba(255,255,255,0.3)", 
              color: "#fff", 
              padding: "8px 16px", 
              borderRadius: "20px",
              cursor: "pointer",
              fontFamily: "'Baloo 2', cursive",
              fontSize: "0.95rem",
              backdropFilter: "blur(4px)",
              textAlign: "left"
            }}
          >
            {getSoundButtonText()}
          </button>
          <button 
            onClick={goHowToUse}
            style={{ 
              background: "transparent", 
              border: "2px solid rgba(255,255,255,0.3)", 
              color: "#fff", 
              width: "42px",
              height: "42px",
              display: "flex",
              alignItems: "center",
              justifyContent: "center",
              borderRadius: "50%",
              cursor: "pointer",
              fontFamily: "'Baloo 2', cursive",
              fontSize: "1.2rem",
              fontWeight: "900",
              backdropFilter: "blur(4px)",
              flexShrink: 0
            }}
            title="Nasıl Kullanılır?"
          >
            ?
          </button>
        </div>
      </div>

      {/* Sürüm Bilgisi */}
      <div style={{ position: "absolute", bottom: "6px", width: "100%", textAlign: "center", fontSize: "0.75rem", color: "#6a9a7a", fontWeight: "800", opacity: 0.8, zIndex: 10 }}>
        V.0.2.2
      </div>

      {showSingleModal && (
        <GameSingleConfigModal onClose={() => setShowSingleModal(false)} />
      )}
    </div>
  );
}
