import React, { useState, useEffect } from 'react';
import { useApp } from '../context/AppContext';
import './InstructionalPage.css';

export default function InstructionalPage() {
  const { goHome } = useApp();
  const [animState, setAnimState] = useState('idle'); // 'idle', 'front', 'back'

  useEffect(() => {
    let timer;
    console.log("🔄 Durum değişti:", animState);
    
    if (animState !== 'idle') {
      timer = setTimeout(() => {
        console.log("⏳ 1 Saniye doldu, 'idle' (bekleme) pozisyonuna dönülüyor..");
        setAnimState('idle');
      }, 1000);
    }
    return () => clearTimeout(timer);
  }, [animState]);

  const handleFrontClick = () => {
    console.log("👉 ÖN butonuna tıklandı!");
    setAnimState('front');
  };
  
  const handleBackClick = () => {
    console.log("👉 ARKA butonuna tıklandı!");
    setAnimState('back');
  };

  // SVG Paths with identical point counts (1 MoveTo, 1 QuadCurve) for CSS transition
  const lineIdle = "M 130,220 Q 220,220 310,220";
  const lineFront = "M 120,95 Q 160,220 310,220";
  const lineBack = "M 130,220 Q 250,70 310,220";

  const currentPath = animState === 'idle' ? lineIdle : animState === 'front' ? lineFront : lineBack;

  // Head position
  const headPos = {
    idle: { x: 130, y: 220, rotate: 0 },
    front: { x: 120, y: 95, rotate: -35 },
    back: { x: 130, y: 220, rotate: 10 }
  };
  const currentHead = headPos[animState];

  return (
    <div className="instructional-page">
      <div className="instructional-header">
        <h1 className="instructional-title">Dilim Nerede?</h1>
        <p className="instructional-subtitle">
          Tırtıl senin dilin! Tırtılın ağzının içinde nasıl hareket ettiğini görmek için butonlara bas.
        </p>
      </div>

      <div className="mouth-container">
        <svg viewBox="0 0 400 300" className="mouth-svg">
          {/* Yüz Silueti - Alın, Burun, Üst Dudak ve Ağız Açıklığı */}
          <path d="M 60,10 Q 50,30 20,45 Q -10,65 10,75 Q 30,85 40,85 L 100,80" 
                fill="none" stroke="#f1c27d" strokeWidth="8" strokeLinecap="round" strokeLinejoin="round"/>
          
          {/* Göz */}
          <path d="M 60,50 Q 70,45 80,50" fill="none" stroke="#cfa05d" strokeWidth="4" strokeLinecap="round" />

          {/* Alt Dudak, Çene, Ağız Açıklığı Alt Kısmı ve Boyun */}
          <path d="M 100,240 L 40,230 Q 10,250 40,270 Q 50,290 50,300" 
                fill="none" stroke="#f1c27d" strokeWidth="8" strokeLinecap="round" strokeLinejoin="round"/>
          
          {/* Palate (Damak) */}
          <path d="M 100,80 Q 180,50 250,80 Q 300,110 320,160" 
                fill="none" stroke="#ffbba6" strokeWidth="6" strokeLinecap="round" strokeDasharray="6,6"/>
          
          {/* Upper Teeth (Üst Dişler) */}
          <rect x="100" y="80" width="12" height="24" rx="4" fill="#ffffff" stroke="#ddd" strokeWidth="2" transform="rotate(-15 100 80)" />
          
          {/* Lower Jaw / Floor of mouth (Alt çene / Dil tabanı) */}
          <path d="M 100,240 Q 200,250 320,240" 
                fill="none" stroke="#ffbba6" strokeWidth="6" strokeLinecap="round"/>

          {/* Lower Teeth (Alt Dişler) */}
          <rect x="100" y="216" width="12" height="24" rx="4" fill="#ffffff" stroke="#ddd" strokeWidth="2" transform="rotate(15 100 240)" />

          {/* Throat Back (Boğaz Arkası) */}
          <path d="M 320,160 Q 340,200 320,240" 
                fill="none" stroke="#ffbba6" strokeWidth="6" strokeLinecap="round" strokeDasharray="4,6"/>
          
          {/* Tongue Body (Dil Gövdesi) */}
          <path 
            className="tongue-path"
            d={currentPath} 
            fill="none" 
            stroke="#ff7675"  /* Pembe / Dil rengi */
            strokeWidth="45" 
            strokeLinecap="round" 
            strokeLinejoin="round" 
          />
          
          {/* Taste Buds / Texture (Tat tomurcukları) */}
          <path 
            className="tongue-path"
            d={currentPath} 
            fill="none" 
            stroke="#ff4757" 
            strokeWidth="30" 
            strokeLinecap="round" 
            strokeDasharray="2, 15"
            opacity="0.6"
          />

          {/* Character Head (Dil Başı / Yüz) */}
          <g 
            className="tongue-head"
            style={{ 
               transform: `translate3d(${currentHead.x}px, ${currentHead.y}px, 0) rotate(${currentHead.rotate}deg)`,
              transformOrigin: '0px 0px',
              willChange: 'transform'
            }}
          >
            {/* Base Head */}
            <circle cx="0" cy="0" r="24" fill="#ff7675" />
            {/* Eye Background */}
            <circle cx="-6" cy="-8" r="6" fill="white" />
            <circle cx="8" cy="-8" r="6" fill="white" />
            {/* Eye Pupil */}
            <circle cx="-6" cy="-8" r="3" fill="#333" />
            <circle cx="8" cy="-8" r="3" fill="#333" />
            {/* Smile / Mouth */}
            <path d="M -8,6 Q 0,14 8,6" fill="none" stroke="#d63031" strokeWidth="3" strokeLinecap="round" />
            
            {/* Removed the insect antennae to make it look more like a cute tongue */}
          </g>

          {/* Markers / Labels inside SVG */}
          <text x="130" y="65" fontSize="14" fill="#888" fontWeight="bold">ÖN</text>
          <text x="240" y="60" fontSize="14" fill="#888" fontWeight="bold">ARKA</text>
        </svg>
      </div>

      <div className="instructional-buttons">
        <button 
          className="btn-instructional btn-front" 
          onClick={handleFrontClick}
        >
          ÖN
        </button>
        <button 
          className="btn-instructional btn-back" 
          onClick={handleBackClick}
        >
          ARKA
        </button>
      </div>

      <button className="btn-back-home" onClick={goHome}>
        ⬅ Ana Ekrana Dön
      </button>
    </div>
  );
}
