// Yeni kelime çifti ekleme modalı
// Props:
//   onClose  () => void
//   onSave   (pair) => void

import { useState } from "react";

const POSITION_OPTIONS = [
  { value: "front", label: "🌟 Ön (Front)" },
  { value: "back",  label: "🔆 Arka (Back)" },
];

const EMPTY_FORM = {
  word1: "",
  word2: "",
  position1: "front",
  word1Img: "",
  word2Img: "",
};

export default function AddWordModal({ onClose, onSave, initialData }) {
  const [form, setForm]     = useState(initialData || EMPTY_FORM);
  const [errors, setErrors] = useState({});

  const update = (field, value) => {
    setForm((prev) => ({ ...prev, [field]: value }));
    if (errors[field]) setErrors((prev) => ({ ...prev, [field]: "" }));
  };

  const validate = () => {
    const errs = {};
    if (!(form.word1 || "").trim()) errs.word1 = "Bu alan zorunludur.";
    if (!(form.word2 || "").trim()) errs.word2 = "Bu alan zorunludur.";
    return errs;
  };

  const handleSave = () => {
    const errs = validate();
    if (Object.keys(errs).length > 0) { setErrors(errs); return; }

    onSave({
      word1:    (form.word1 || "").trim(),
      word2:    (form.word2 || "").trim(),
      position1: form.position1 || "front",
      position2: form.position2 || "front",
      word1Img:   (form.word1Img || "").trim() || null,
      word2Img:   (form.word2Img || "").trim() || null,
    });
    onClose();
  };

  // Overlay'e tıklanınca kapat
  const handleOverlayClick = (e) => {
    if (e.target === e.currentTarget) onClose();
  };

  return (
    <div className="modal-overlay" onClick={handleOverlayClick}>
      <div className="modal">
        <h2 className="modal__title">
          {initialData ? "✏️ Kelime Çiftini Düzenle" : "➕ Yeni Kelime Çifti"}
        </h2>

        <div className="modal__columns">
          {/* --- 1. KELİME GRUBU --- */}
          <div className="modal__column">
            <h3 className="modal__column-title">1. Kelime Ayarları</h3>
            
            <div className="modal__field">
              <label className="modal__label">Kelime Adı *</label>
              <input
                className={`modal__input${errors.word1 ? " error" : ""}`}
                placeholder="örn: top"
                value={form.word1 || ""}
                onChange={(e) => update("word1", e.target.value)}
              />
              {errors.word1 && <span className="modal__error">{errors.word1}</span>}
            </div>

            <div className="modal__field">
              <label className="modal__label">Lingual Pozisyon</label>
              <select
                className="modal__select"
                value={form.position1}
                onChange={(e) => update("position1", e.target.value)}
              >
                {POSITION_OPTIONS.map((opt) => (
                  <option key={opt.value} value={opt.value}>{opt.label}</option>
                ))}
              </select>
            </div>

            <div className="modal__field">
              <label className="modal__label">1. Kelime Görsel URL (Opsiyonel)</label>
              <input
                className="modal__input"
                placeholder="https://... veya /images/abc.png"
                value={form.word1Img || ""}
                onChange={(e) => update("word1Img", e.target.value)}
              />
            </div>
          </div>

          <div className="modal__divider" />

          {/* --- 2. KELİME GRUBU --- */}
          <div className="modal__column">
            <h3 className="modal__column-title">2. Kelime Ayarları</h3>
            
            <div className="modal__field">
              <label className="modal__label">Kelime Adı *</label>
              <input
                className={`modal__input${errors.word2 ? " error" : ""}`}
                placeholder="örn: dop"
                value={form.word2 || ""}
                onChange={(e) => update("word2", e.target.value)}
              />
              {errors.word2 && <span className="modal__error">{errors.word2}</span>}
            </div>

            <div className="modal__field">
              <label className="modal__label">Lingual Pozisyon</label>
              <select
                className="modal__select"
                value={form.position2}
                onChange={(e) => update("position2", e.target.value)}
              >
                {POSITION_OPTIONS.map((opt) => (
                  <option key={opt.value} value={opt.value}>{opt.label}</option>
                ))}
              </select>
            </div>

            <div className="modal__field">
              <label className="modal__label">2. Kelime Görsel URL (Opsiyonel)</label>
              <input
                className="modal__input"
                placeholder="https://... veya /images/abc.png"
                value={form.word2Img || ""}
                onChange={(e) => update("word2Img", e.target.value)}
              />
            </div>
          </div>
        </div>

        {/* Aksiyonlar */}
        <div className="modal__actions">
          <button className="modal__btn modal__btn--cancel" onClick={onClose}>
            İptal
          </button>
          <button className="modal__btn modal__btn--save" onClick={handleSave}>
            💾 Kaydet
          </button>
        </div>
      </div>
    </div>
  );
}
